    A --> C["AffiliateType"]

    subgraph ServiceType
        B1(Unknown)
        B2(ChannelDeepLink)
    end

    subgraph AffiliateType
        C1(Unknown)
        C2(WOM)
        C3(PCS)
        C4(IM)
        C5(SFC)
        C6(ETC)
    end

