    server_name linkrew-local.gmarket.co.kr;
    ssl_certificate /etc/jdcm/cert.pem;
    ssl_certificate_key /etc/jdcm/key.pem;
    ssl_password_file    /etc/jdcm/key.passwd;

    location / {
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
